#include<bits/stdc++.h>
using namespace std;
#define ll long long
const int N=1000005,mod=1e9+7;
ll n,m,dp[N][2];
vector<int> g[N];
void dfs(int u,int f)
{
	dp[u][0]=dp[u][1]=1;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(v==f) continue;
		dfs(v,u);
		dp[u][0]=dp[u][0]*(dp[v][0]+dp[v][1]*m%mod)%mod;
		dp[u][1]=dp[u][1]*(dp[v][0]+dp[v][1]*(m-1)%mod)%mod;
	}
}
int main()
{
//	ios::sync_with_stdio(0);
//	cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1;i<n;i++)
	{
		int u,v;
		cin>>u>>v;
		g[u].push_back(v);
		g[v].push_back(u);
	}
	dfs(1,0);
	cout<<(dp[1][0]+dp[1][1]*m%mod)%mod;
	return 0;
}
